const ROUTE_ROLES: Record<string, string[]> = {
  superadmin: ["superadmin"],
  admin: ["superadmin", "admin"],
  manager: ["superadmin", "admin", "manager"],
  reception: ["superadmin", "admin", "manager", "reception"],
  staff: ["superadmin", "admin", "manager", "staff"],
  hall: ["superadmin", "admin", "manager", "reception", "staff", "hall"],
  kitchen: ["superadmin", "admin", "manager", "kitchen"],
  purchasing: ["superadmin", "admin", "procurement", "procurement_manager", "procurement_staff", "purchasing"],
  accounting: ["superadmin", "admin", "accounting", "accounting_manager", "manager"],
  crm: ["superadmin", "admin", "manager", "crm_manager", "crm"],
  marketing: ["superadmin", "admin", "manager", "marketing"],
  bod: ["superadmin", "admin", "bod"],
  tablet: ["superadmin", "admin", "manager", "reception", "staff", "customer"],
};

router.beforeEach(async (to) => {
  const { isAuthenticated, loading, role, isAdmin } = useAuth();

  if (loading.value) {
    await new Promise<void>((resolve) => {
      const check = setInterval(() => {
        if (!loading.value) {
          clearInterval(check);
          resolve();
        }
      }, 50);
    });
  }

  console.log(
    "[DEBUG ROUTER] Navigating to:",
    to.path,
    "requiresAuth:",
    to.meta.requiresAuth,
    "isAuthenticated:",
    isAuthenticated.value,
  );

  // Public routes.
  if (to.meta.requiresAuth === false) {
    console.log(
      "[DEBUG ROUTER] Bypass match for public customer route:",
      to.path,
    );
    if (isAuthenticated.value && to.name === "login" && role.value) {
      const fallback = getFallbackRouteForRole(role.value);
      if (typeof fallback === 'object' && fallback !== null && 'name' in fallback && fallback.name === 'login') {
        return; // Prevent infinite loop if role has no home mapped
      }
      return fallback;
    }
    return;
  }

  if (!isAuthenticated.value) {
    console.warn(
      "[DEBUG ROUTER] Redirecting to login: User not authenticated for route",
      to.path,
    );
    return { name: "login" };
  }

  const { activeBranchId } = useBranch();
  const needsBranch = to.meta.requiresBranch ?? true;
  if (needsBranch && !activeBranchId.value) {
    if (isAdmin.value && to.name !== "SelectBranch") {
      return { name: "SelectBranch" };
    }
  }

  const prefix = String(to.path.split("/")[1] ?? "");
  const allowed = ROUTE_ROLES[prefix];

  // Normalize checking
  const currentRole = role.value;

  if (allowed && currentRole && !allowed.includes(currentRole)) {
    return getFallbackRouteForRole(currentRole);
  }

  console.log("[DEBUG ROUTER] Navigation allowed to:", to.path);
  return;
});

export default router;

// File: src/composables/useReceptionSync.ts
//
// Thin wrapper around `useReceptionStore` (Pinia) that auto-loads
// reservations on mount and exposes a simplified API for components.
//
// Usage in any reception view:
//   const { reservations, waitingList, addReservation, assignTable } = useReceptionSync()
//
// Pinia reactivity handles cross-component sync automatically — no
// CustomEvent / window dispatch is needed. When component A calls
// `assignTable`, component B's `waitingReservations` computed updates
// in the same tick.

import { onMounted } from 'vue'
import { storeToRefs } from 'pinia'
import { useReceptionStore } from '@/stores/receptionStore'

export function useReceptionSync(options?: { autoLoad?: boolean }) {
  const store = useReceptionStore()
  const autoLoad = options?.autoLoad ?? true

  // Destructure reactive state + getters with storeToRefs so they
  // stay reactive (plain destructuring would break reactivity).
  const {
    reservations,
    activeSessions,
    lastUpdated,
    isLoaded,
    todayReservations,
    waitingReservations,
    seatedReservations,
    pendingCount,
    confirmedCount,
    seatedCount,
    completedCount,
    cancelledCount,
  } = storeToRefs(store)

  // Auto-load on mount unless the caller opts out
  onMounted(() => {
    if (autoLoad) {
      store.loadReservations()
    }
  })

  return {
    // State (reactive refs)
    reservations,
    activeSessions,
    lastUpdated,
    isLoaded,

    // Getters (reactive refs)
    todayReservations,
    waitingReservations,
    seatedReservations,
    pendingCount,
    confirmedCount,
    seatedCount,
    completedCount,
    cancelledCount,

    // Actions (store methods, stable references)
    loadReservations: store.loadReservations,
    addReservation: store.addReservation,
    updateReservation: store.updateReservation,
    deleteReservation: store.deleteReservation,
    assignTable: store.assignTable,
    releaseTable: store.releaseTable,
    getSessionByTable: store.getSessionByTable,
    getReservationByTable: store.getReservationByTable,
    resetState: store.resetState,
    resetToMock: store.resetToMock,
    persistToStorage: store.persistToStorage,
    loadFromStorage: store.loadFromStorage,
  }
}

export default useReceptionSync

import { ref } from 'vue'
import { supabase } from '@/lib/supabase'
import type { Zone, TableT, TableStatus } from '@/types/database'
import { useBranch, throwBranchGuard } from '@/composables/useBranch'

export function useTable() {
  const { activeBranchId } = useBranch()
  const loading = ref(false)
  const error = ref<string | null>(null)

  async function listZones(): Promise<Zone[]> {
    loading.value = true
    error.value = null
    const tables = await listTables()
    loading.value = false
    const unique = [...new Set((tables || []).map((t: any) => t.zone))]
    return unique.map(z => ({
      id: String(z),
      branch_id: (activeBranchId.value ?? throwBranchGuard()),
      name: String(z),
      color: '#4ade80' // default color
    })) as Zone[]
  }

  async function listTables(): Promise<TableT[]> {
    const { data, error: err } = await supabase.rpc('hall_list_tables', {
      p_branch_id: activeBranchId.value ?? throwBranchGuard(),
    })

    if (err) {
      console.error('Error fetching tables:', err)
      return []
    }
    return data as TableT[]
  }

  async function updateStatus(tableId: string, status: TableStatus): Promise<void> {
    throw new Error(
      `Direct table status updates are not allowed from the frontend (${tableId} -> ${status}). Use a Hall RPC/action flow.`,
    )
  }

  return { loading, error, listZones, listTables, updateStatus }
}

