/* ============================================
   NGƯU CÁT - Orange & White Theme
   ============================================ */

@layer base {
  :root {
    /* Backgrounds */
    --background: 0 0% 100%;          /* White */
    --foreground: 24 10% 15%;          /* Dark gray-orange text */

    /* Cards */
