    /* Secondary - Soft Orange */
    --secondary: 24 100% 95%;          /* #FFEEE5 */
    --secondary-foreground: 24 100% 35%;

    /* Muted - Cream/White */
    --muted: 24 100% 97%;              /* #FFF8F5 */
    --muted-foreground: 24 10% 50%;

    /* Accent - Light orange */
    --accent: 24 100% 95%;
    --accent-foreground: 24 100% 35%;

    /* Destructive */
    --destructive: 0 84% 60%;
    --destructive-foreground: 0 0% 100%;

    /* Borders & inputs */
