    --popover: 24 20% 14%;
    --popover-foreground: 0 0% 100%;
    --primary: 24 100% 55%;
    --primary-foreground: 0 0% 100%;
    --secondary: 24 20% 20%;
    --secondary-foreground: 0 0% 100%;
    --muted: 24 20% 20%;
    --muted-foreground: 24 10% 65%;
    --accent: 24 20% 20%;
    --accent-foreground: 0 0% 100%;
    --destructive: 0 84% 60%;
    --destructive-foreground: 0 0% 100%;
    --border: 24 20% 20%;
    --input: 24 20% 20%;
    --ring: 24 100% 55%;
  }
}

@layer base {
  * {
    @apply border-border;
  }
  html, body {
    height: 100%;
  }
  body {
    @apply bg-background text-foreground;
    font-family: 'Nunito', -apple-system, BlinkMacSystemFont, 'Hiragino Sans', 'Yu Gothic', sans-serif;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
  }
  #app {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
  }
}

/* ============================================
   Custom utilities
   ============================================ */
@layer components {
  .kawaii-shadow {
    box-shadow: 0 4px 14px rgba(255, 103, 46, 0.15);
  }
  .kawaii-shadow-lg {
    box-shadow: 0 10px 28px rgba(255, 103, 46, 0.2);
  }
  .kawaii-gradient {
    background: linear-gradient(135deg, #FF8E61 0%, #FF672E 100%);
  }
  .kawaii-card {
    @apply bg-white rounded-xl border border-[hsl(var(--border))] shadow-sm transition-all;
  }
  .kawaii-card-header {
    @apply px-5 py-3 border-b border-[hsl(var(--border))] flex items-center justify-between bg-[hsl(var(--muted))]/50 rounded-t-xl;
  }
  .kawaii-btn-primary {
    @apply kawaii-gradient text-white font-bold tracking-wide border-0 rounded-xl transition-all shadow-md hover:shadow-lg;
  }
  .kawaii-btn-primary:hover {
    filter: brightness(1.05);
  }
  .kawaii-btn-primary:active {
    transform: translateY(1px);
    box-shadow: 0 2px 5px rgba(255, 103, 46, 0.3);
  }
  .kawaii-btn-ghost {
    @apply bg-white border border-[hsl(var(--border))] rounded-xl text-foreground font-bold hover:bg-[hsl(var(--muted))] transition-colors;
  }
  .kawaii-pill {
    @apply inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-semibold;
  }
  .kawaii-input {
    @apply w-full bg-white border border-[hsl(var(--border))] rounded-xl text-foreground px-4 outline-none transition-all focus:border-[hsl(var(--primary))] focus:ring-1 focus:ring-[hsl(var(--primary))];
  }
  .kawaii-tab-active {
    @apply border-[hsl(var(--primary))] text-[hsl(var(--primary))] bg-[hsl(var(--primary))]/10;
  }
}

/* Custom scrollbar */
